+					logging.Warn(logCtx, "prepare-commit-msg: failed to save commit_linking=always",
+						slog.String("error", saveErr.Error()),
+					)
+				}
+			}
 			message = addCheckpointTrailer(message, checkpointID)
 		}
 	default:
